const PIE_COLORS = ['#ef4444', '#f59e0b', '#3b82f6', '#8b5cf6', '#64748b'];
const MONTH_COLORS = { 'Заказы': '#22c55e', 'Сделка сорвалась': '#eab308', 'Не прошли по цене': '#ef4444', 'Прочие потери': '#f97316', 'Нет обратной связи': '#6366f1' };

const monthToTimestamp = (name) => {
  const months = { 'январь':0,'февраль':1,'март':2,'апрель':3,'май':4,'июнь':5,'июль':6,'август':7,'сентябрь':8,'октябрь':9,'ноябрь':10,'декабрь':11 };
  const parts = name.split(' '); if (parts.length < 2) return 0;
  return (parseInt(parts[1]) || 2000) * 100 + (months[parts[0].toLowerCase()] ?? 0);
};
const sortMonths = (months) => [...months].sort((a, b) => monthToTimestamp(a) - monthToTimestamp(b));

const HISTORY_KEY = 'dashboard_history', THEME_KEY = 'dashboard_theme', API_KEY_STORAGE = 'deepseek_api_key';
const MONTHLY_DATA_KEY = 'kubarev_monthly_data', GOALS_KEY = 'dashboard_goals', ADMIN_KEY = 'dashboard_admin';
const MAX_HISTORY = 5;

const hashPassword = async (pw) => { const d = new TextEncoder().encode(pw); const h = await crypto.subtle.digest('SHA-256', d); return Array.from(new Uint8Array(h)).map(b => b.toString(16).padStart(2, '0')).join(''); };
const loadMonthlyData = () => { try { return JSON.parse(localStorage.getItem(MONTHLY_DATA_KEY) || '{}'); } catch { return {}; } };
const saveMonthlyData = (d) => { localStorage.setItem(MONTHLY_DATA_KEY, JSON.stringify(d)); };
const monthlyDataToMd = (data) => {
  const allKeys = sortMonths(Object.keys(data));
  let md = `# Данные запросов: Кубарев Михаил\n\n> Автосохранено\n\n`;
  for (const m of allKeys) { if (!data[m]) continue; const cats = data[m].categories || []; if (!cats.length) continue; md += `## ${m}\n\n| Исполнитель | Категория | Заказ | Сделка сорвалась | Не прошли по цене | Долго считали | Клиент не отвечает | Формальный запрос | Нет обратной связи | Всего |\n| --- | --- | --- | --- | --- | --- | --- | --- | --- | --- |\n`; for (const c of cats) { const t = (v) => v === 0 ? '' : v; md += `| Кубарев Михаил | ${c.category} | ${t(c.order)} | ${t(c.dealFell)} | ${t(c.priceFail)} | ${t(c.slowCalc)} | ${t(c.clientSilent)} | ${t(c.formal)} | ${t(c.noFeedback)} | ${c.total} |\n`; } md += '\n'; }
  return md || DEFAULT_TEXT;
};

const aggregateByCategory = (rows) => { const m = {}; for (const r of rows) { if (!m[r.category]) m[r.category] = { name: r.category, 'Заказ': 0, 'Сделка сорвалась': 0, 'Не прошли по цене': 0, 'Прочие потери': 0 }; m[r.category]['Заказ'] += r.order; m[r.category]['Сделка сорвалась'] += r.dealFell; m[r.category]['Не прошли по цене'] += r.priceFail; m[r.category]['Прочие потери'] += r.slowCalc + r.clientSilent + r.formal + r.noFeedback; } return Object.values(m); };
const aggregateLossReasons = (rows) => { let pf=0,sc=0,cs=0,f=0,nf=0; for (const r of rows) { pf+=r.priceFail; sc+=r.slowCalc; cs+=r.clientSilent; f+=r.formal; nf+=r.noFeedback; } return [{ name: 'Не прошли по цене', value: pf },{ name: 'Долго считали', value: sc },{ name: 'Клиент не отвечает', value: cs },{ name: 'Формальный запрос', value: f },{ name: 'Нет обратной связи', value: nf }].filter(d => d.value > 0); };
const aggregateByMonth = (rows) => { const m = {}; for (const r of rows) { if (!m[r.month]) m[r.month] = { month: r.month, 'Заказы':0,'Сделка сорвалась':0,'Не прошли по цене':0,'Прочие потери':0,'Нет обратной связи':0, total:0, orders:0, junk:0, noFeedbackRaw:0, formalRaw:0 }; m[r.month]['Заказы']+=r.order; m[r.month]['Сделка сорвалась']+=r.dealFell; m[r.month]['Не прошли по цене']+=r.priceFail; m[r.month]['Прочие потери']+=r.slowCalc+r.clientSilent; m[r.month]['Нет обратной связи']+=r.formal+r.noFeedback; m[r.month].total+=r.total; m[r.month].orders+=r.order; m[r.month].junk+=r.formal+r.noFeedback; m[r.month].noFeedbackRaw+=r.noFeedback; m[r.month].formalRaw+=r.formal; } return sortMonths(Object.keys(m)).map(x => m[x]); };
const aggregateConversionByMonth = (rows) => { const m={}; for (const r of rows) { if (!m[r.month]) m[r.month]={ month: r.month, total:0, orders:0 }; m[r.month].total+=r.total; m[r.month].orders+=r.order; } return sortMonths(Object.keys(m)).map(x=>({ month: x, conv: m[x].total > 0 ? +((m[x].orders/m[x].total)*100).toFixed(1) : 0 })); };

const generateInsights = (rows) => {
  const ins=[]; if(!rows.length) return ins;
  let t=0,pf=0,cs=0,f=0,nf=0,o=0,df=0,sc=0; for (const r of rows) { t+=r.total; pf+=r.priceFail; cs+=r.clientSilent; f+=r.formal; nf+=r.noFeedback; o+=r.order; df+=r.dealFell; sc+=r.slowCalc; } if(t===0) return ins;
  const push=(cat,i)=>ins.push({...i,category:cat});
  const noFb=((cs+nf)/t)*100; if(noFb>20) push('attention',{ type:'warning',icon:AlertTriangle,color:'yellow',title:'⚠️ Высокий % без фидбека',text:`${noFb.toFixed(1)}% запросов без обратной связи. Внедри Чек-лист квалификации для ОП.` });
  const junk=((f+nf)/t)*100; if(junk>50) push('attention',{ type:'danger',icon:AlertTriangle,color:'red',title:'🛑 Критический объём формальных запросов',text:`Формальные + Нет ОС = ${junk.toFixed(0)}% от всех. Требуйте целевую ставку до расчётов.` });
  const pfp=(pf/t)*100; if(pfp>30) push('attention',{ type:'info',icon:CheckCircle,color:'blue',title:'📉 Много отказов по цене',text:`${pfp.toFixed(1)}% отказов из-за цены. Пересмотри тарифы FOB с агентами.` });
  const conv=aggregateConversionByMonth(rows); let dec=0; for(let i=1;i<conv.length;i++){ if(conv[i].conv<conv[i-1].conv){ dec++; if(dec>=2){ push('attention',{ type:'danger',icon:AlertTriangle,color:'red',title:'📉 Конверсия падает 2+ месяца',text:`С ${conv[i-1].month} (${conv[i-1].conv}%) до ${conv[i].month} (${conv[i].conv}%). Проверь рынок.` }); break; } } else dec=0; }
  const md=aggregateByMonth(rows); const peak=md.find(d=>d.total>130); if(peak) push('attention',{ type:'warning',icon:AlertTriangle,color:'yellow',title:'📈 Пиковая нагрузка',text:`${peak.month}: ${peak.total} запросов. Планируй ресурсы.` });
  let rise=0; for(let i=1;i<conv.length;i++){ if(conv[i].conv>conv[i-1].conv){ rise++; if(rise>=2){ push('strength',{ type:'success',icon:CheckCircle,color:'green',title:'🚀 Конверсия растёт!',text:`С ${conv[i-1].month} (${conv[i-1].conv}%) до ${conv[i].month} (${conv[i].conv}%). Отличная работа!` }); break; } } else rise=0; }
  if(sc>3) push('attention',{ type:'danger',icon:AlertTriangle,color:'red',title:'🐢 Задержка расчётов',text:`${sc} запросов с долгим расчётом (обычно 0–2). Проверь данные поставщиков.` });
  const dfp=o>0?(df/(o+df))*100:0; if(dfp>20&&df>5) push('attention',{ type:'info',icon:Info,color:'blue',title:'🤝 Срываются сделки',text:`${dfp.toFixed(0)}% успешных по цене сорвались (${df} из ${o+df}). Проверь условия.` });
  const best=md.filter(d=>d.orders>3).sort((a,b)=>(b.orders/(b.total||1))-(a.orders/(a.total||1)))[0]; if(best){ const bc=best.total>0?((best.orders/best.total)*100).toFixed(0):0; push('strength',{ type:'success',icon:CheckCircle,color:'green',title:'🏆 Лучший месяц',text:`${best.month}: конверсия ${bc}% (${best.orders} заказов из ${best.total}). Бенчмарк!` }); }
  const worst=md.filter(d=>d.total>20).sort((a,b)=>(a.orders/(a.total||1))-(b.orders/(b.total||1)))[0]; if(worst&&best&&worst.month!==best.month){ const wc=worst.total>0?((worst.orders/worst.total)*100).toFixed(0):0; const reason=worst.noFeedbackRaw>worst.formalRaw?`нет ОС (${worst.noFeedbackRaw})`:`формальных (${worst.formalRaw})`; push('attention',{ type:'danger',icon:AlertTriangle,color:'red',title:'📉 Худший месяц',text:`${worst.month}: конверсия ${wc}% (${worst.orders} из ${worst.total}). Причина: ${reason}.` }); }
  if(sc<=3&&t>50) push('strength',{ type:'success',icon:CheckCircle,color:'green',title:'⚡ Высокая оперативность',text:`Всего ${sc} запросов с задержкой из ${t} (${((sc/t)*100).toFixed(1)}%). Ты очень быстрый — это твой козырь!` });
  return ins;
};

const applyFilters = (rows,catF,mc,yF,mnF) => { let f=rows; if(catF!=='all') f=f.filter(r=>r.category===catF); if(yF!=='all') f=f.filter(r=>r.month.includes(yF)); if(mnF!=='all') f=f.filter(r=>r.month.startsWith(mnF)); if(mc>0){ const am=sortMonths([...new Set(f.map(r=>r.month))]); f=f.filter(r=>am.slice(-mc).includes(r.month)); } return f; };

const AnimatedNumber = ({ value, duration = 1200, isPercent = false }) => { const [dv,setDv]=useState(0); const tv=parseFloat(value)||0; useEffect(()=>{ let st,af; const anim=(t)=>{ if(!st)st=t; const p=Math.min((t-st)/duration,1); setDv(tv*(1-Math.pow(1-p,3))); if(p<1) af=requestAnimationFrame(anim); else setDv(tv); }; af=requestAnimationFrame(anim); return ()=>cancelAnimationFrame(af); },[tv,duration]); return <span>{isPercent?dv.toFixed(1):Math.round(dv)}{isPercent?'%':''}</span>; };
const Sparkline = ({ data, dataKey, color, invert = false }) => { if(!data||data.length<2) return <div className="w-12 h-6"/>; const vals=data.map(d=>{ if(dataKey==='conversion') return d.total>0?(d.orders/d.total)*100:0; if(dataKey==='junkPct') return d.total>0?(d.junk/d.total)*100:0; return d[dataKey]||0; }); const min=Math.min(...vals),max=Math.max(...vals),r=max-min||1; const pts=vals.map((v,i)=>{ const x=(i/(vals.length-1))*48; let y=24-((v-min)/r)*20; if(invert) y=((v-min)/r)*20; return `${x},${y}`; }).join(' L '); return <svg width="48" height="24" className="overflow-visible"><path d={`M ${pts}`} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>; };
const InsightCard = ({ insight }) => { const c={ red:{ border:'border-red-400',bg:'bg-red-50/80 dark:bg-red-900/15',text:'text-red-800 dark:text-red-300',sub:'text-red-600 dark:text-red-400',icon:'text-red-500'},yellow:{ border:'border-amber-400',bg:'bg-amber-50/80 dark:bg-amber-900/15',text:'text-amber-800 dark:text-amber-300',sub:'text-amber-600 dark:text-amber-400',icon:'text-amber-500'},blue:{ border:'border-blue-400',bg:'bg-blue-50/80 dark:bg-blue-900/15',text:'text-blue-800 dark:text-blue-300',sub:'text-blue-600 dark:text-blue-400',icon:'text-blue-500'},green:{ border:'border-emerald-400',bg:'bg-emerald-50/80 dark:bg-emerald-900/15',text:'text-emerald-800 dark:text-emerald-300',sub:'text-emerald-600 dark:text-emerald-400',icon:'text-emerald-500'} }[insight.color]||{ border:'border-slate-300',bg:'bg-slate-50',text:'text-slate-700',sub:'text-slate-500',icon:'text-slate-400'}; return <div className={`${c.bg} border-l-4 ${c.border} p-4 rounded-r-2xl flex items-start gap-3 hover:translate-x-1 transition-transform`}><insight.icon className={`${c.icon} mt-0.5 flex-shrink-0`}/><div><h4 className={`font-semibold ${c.text} text-sm`}>{insight.title}</h4><p className={`${c.sub} text-xs`}>{insight.text}</p></div></div>; };
const TrendArrow = ({ current, previous, invert = false }) => { if(previous===null||previous===undefined||previous===0) return null; const diff=+(current-previous).toFixed(1),pct=+((diff/previous)*100).toFixed(1); const good=invert?diff<0:diff>0,bad=invert?diff>0:diff<0; const cc=good?'text-green-600 dark:text-green-400':bad?'text-red-600 dark:text-red-400':'text-slate-400'; const I=good?ArrowUp:bad?ArrowDown:Minus; return <span className={`inline-flex items-center gap-0.5 text-xs font-medium ${cc}`}><I className="w-3 h-3"/>{Math.abs(pct)}%</span>; };
const Heatmap = ({ data }) => { if(!data||!data.length) return null; const getC=(d)=>{ if(!d.total) return 'bg-slate-100 dark:bg-slate-800'; const c=(d.orders/d.total)*100; if(c>=20) return 'bg-emerald-400'; if(c>=12) return 'bg-blue-300'; if(c>=6) return 'bg-amber-200'; return 'bg-red-300'; }; const getDkC=(d)=>{ if(!d.total) return 'dark:bg-slate-800'; const c=(d.orders/d.total)*100; if(c>=20) return 'dark:bg-emerald-700'; if(c>=12) return 'dark:bg-blue-800'; if(c>=6) return 'dark:bg-amber-800'; return 'dark:bg-red-900'; }; return <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 mb-6"><h3 className="font-semibold mb-4 dark:text-slate-100">Тепловая карта (объём + конверсия)</h3><div className="flex gap-2 overflow-x-auto pb-3">{data.map((d,i)=>{ const conv=d.total>0?((d.orders/d.total)*100):0; return <div key={i} className="flex flex-col items-center gap-1.5 min-w-[68px]" title={`${d.month}: ${d.total} запр. • ${conv.toFixed(0)}% конверсия • ${d.orders} заказов • ${d.junk} формальных`}><div className="flex flex-col items-center gap-0.5"><div className={`w-full h-16 rounded-xl ${getC(d)} ${getDkC(d)} flex flex-col items-center justify-center px-1 transition-colors`}><span className="text-xs font-bold text-slate-800 dark:text-slate-100 leading-tight">{d.total>0?d.total:''}</span>{d.total>0&&<span className="text-[10px] font-medium text-slate-700 dark:text-slate-200 leading-tight">{conv.toFixed(0)}%</span>}{d.total>0&&<span className="text-[10px] text-slate-500 dark:text-slate-400 leading-tight">{d.orders} зак</span>}</div></div><span className="text-[10px] text-slate-500 dark:text-slate-400 whitespace-nowrap font-medium">{d.month.replace(' 20','\'')}</span></div>; })}</div><div className="flex flex-wrap items-center gap-3 mt-3 text-[10px] text-slate-400 dark:text-slate-500"><span>Конверсия:</span><span className="inline-flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-red-300 dark:bg-red-900"></span>{'<'}6%</span><span className="inline-flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-amber-200 dark:bg-amber-800"></span>6-12%</span><span className="inline-flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-blue-300 dark:bg-blue-800"></span>12-20%</span><span className="inline-flex items-center gap-1"><span className="w-3 h-3 rounded-sm bg-emerald-400 dark:bg-emerald-700"></span>20%+</span></div></div>; };
const KpiTooltip = ({ children, formula, sparkData, sparkColor, sparkKey, invertSpark }) => { const [show,setShow]=useState(false); return <div className="relative" onMouseEnter={()=>setShow(true)} onMouseLeave={()=>setShow(false)}>{children}{show&&<div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 z-30 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-xl p-3 min-w-[220px] animate-in fade-in duration-200"><p className="text-xs text-slate-500 dark:text-slate-400 mb-1">{formula}</p>{sparkData?.length>=2&&<div className="flex justify-center mb-1"><Sparkline data={sparkData} dataKey={sparkKey} color={sparkColor} invert={invertSpark}/></div>}<div className="absolute top-full left-1/2 -translate-x-1/2 -mt-1 w-2 h-2 rotate-45 bg-white dark:bg-slate-800 border-r border-b border-slate-200 dark:border-slate-700"></div></div>}</div>; };

const Dashboard = () => {
  const [monthlyData, setMonthlyData] = useState(loadMonthlyData);
  const [rawText, setRawText] = useState(() => monthlyDataToMd(loadMonthlyData()));
  const [dataSource, setDataSource] = useState('markdown');
  const [excelFileName, setExcelFileName] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [catF, setCatF] = useState('all'), [mc, setMc] = useState(0), [yF, setYF] = useState('all'), [mnF, setMnF] = useState('all');
  const [valErr, setValErr] = useState(0);
  const [history, setHistory] = useState(() => { try { return JSON.parse(localStorage.getItem(HISTORY_KEY) || '[]'); } catch { return []; } });
  const [theme, setTheme] = useState(() => localStorage.getItem(THEME_KEY) || 'light');
  const [themeManual, setThemeManual] = useState(false);
  const [hiddenSeries, setHiddenSeries] = useState(new Set());
  const [showSettings, setShowSettings] = useState(false);
  const [apiKey, setApiKey] = useState(() => localStorage.getItem(API_KEY_STORAGE) || '');
  const [showChat, setShowChat] = useState(false);
  const [chatMessages, setChatMessages] = useState([]); const [chatInput, setChatInput] = useState(''); const [chatLoading, setChatLoading] = useState(false);
  const [wasteReduction, setWasteReduction] = useState(0);
  const [isAdmin, setIsAdmin] = useState(() => sessionStorage.getItem(ADMIN_KEY) === 'true');
  const [showLogin, setShowLogin] = useState(false); const [loginUser, setLoginUser] = useState(''); const [loginPass, setLoginPass] = useState(''); const [loginError, setLoginError] = useState('');
  const [showMonthPanel, setShowMonthPanel] = useState(false); const [newMonthName, setNewMonthName] = useState(''); const [newMonthText, setNewMonthText] = useState(''); const [editingMonth, setEditingMonth] = useState(null); const [monthExcelName, setMonthExcelName] = useState('');
  const [goals, setGoals] = useState(() => { try { return JSON.parse(localStorage.getItem(GOALS_KEY) || '[]'); } catch { return []; } }); const [newGoal, setNewGoal] = useState('');
  const [showUpdateReminder, setShowUpdateReminder] = useState(false);
  const fileInputRef = useRef(null); const monthFileInputRef = useRef(null); const chatEndRef = useRef(null); const dashboardRef = useRef(null);
  const managerFilter = 'Кубарев Михаил';

  useEffect(() => { setRawText(monthlyDataToMd(monthlyData)); }, [monthlyData]);
  useEffect(() => { document.documentElement.classList.toggle('dark', theme === 'dark'); localStorage.setItem(THEME_KEY, theme); }, [theme]);
  useEffect(() => { const checkTime = () => { const h = new Date().getHours(); if (!themeManual) { if (h >= 21 || h < 6) { if (theme !== 'dark') setTheme('dark'); } else { if (theme !== 'light') setTheme('light'); } } }; checkTime(); const iv = setInterval(() => { if (!themeManual) checkTime(); }, 60000); return () => clearInterval(iv); }, [theme, themeManual]);
  useEffect(() => { const keys = Object.keys(monthlyData); if (keys.length > 0) { const sorted = sortMonths(keys); const lm = sorted[sorted.length - 1].toLowerCase(); const mn = ['январь','февраль','март','апрель','май','июнь','июль','август','сентябрь','октябрь','ноябрь','декабрь']; const d = new Date(); const cm = `${mn[d.getMonth()]} ${d.getFullYear()}`; setShowUpdateReminder(lm !== cm.toLowerCase()); } }, [monthlyData]);
  useEffect(() => { if (chatEndRef.current) chatEndRef.current.scrollIntoView({ behavior: 'smooth' }); }, [chatMessages]);

  const handleLogin = async () => { setLoginError(''); if (loginUser !== 'muxakub') { setLoginError('Неверный логин'); return; } if (await hashPassword(loginPass) === await hashPassword('08250825')) { setIsAdmin(true); sessionStorage.setItem(ADMIN_KEY, 'true'); setShowLogin(false); setLoginUser(''); setLoginPass(''); } else setLoginError('Неверный пароль'); };
  const handleLogout = () => { setIsAdmin(false); sessionStorage.removeItem(ADMIN_KEY); };

  const handleAddMonth = () => { const name = newMonthName.trim(), text = newMonthText.trim(); if (!name || !text) return; const parsed = parseMarkdownTable(`## ${name}\n${text}`, managerFilter); if (!parsed.length) { alert('Не удалось распарсить данные. Проверь формат.'); return; } const cats = parsed.map(r => ({ category: r.category, order: r.order, dealFell: r.dealFell, priceFail: r.priceFail, slowCalc: r.slowCalc, clientSilent: r.clientSilent, formal: r.formal, noFeedback: r.noFeedback, total: r.total })); const upd = { ...monthlyData, [name]: { manager: managerFilter, categories: cats } }; setMonthlyData(upd); saveMonthlyData(upd); setNewMonthName(''); setNewMonthText(''); setShowMonthPanel(false); setEditingMonth(null); setMonthExcelName(''); setShowUpdateReminder(false); };
  const handleMonthExcelUpload = async (e) => { const file = e.target.files?.[0]; if (!file) return; setMonthExcelName(file.name); try { const md = await loadExcelAsMarkdown(file, { onlyKubarev: true }); setNewMonthText(md); } catch { alert('❌ Ошибка конвертации Excel.'); } if (monthFileInputRef.current) monthFileInputRef.current.value = ''; };
  const handleDeleteMonth = (month) => { const upd = { ...monthlyData }; delete upd[month]; setMonthlyData(upd); saveMonthlyData(upd); };
  const handleOverwriteMonth = (month) => { setEditingMonth(month); const cats = monthlyData[month]?.categories || []; setNewMonthName(month); setNewMonthText(cats.map(c => `| ${managerFilter} | ${c.category} | ${c.order || ''} | ${c.dealFell || ''} | ${c.priceFail || ''} | ${c.slowCalc || ''} | ${c.clientSilent || ''} | ${c.formal || ''} | ${c.noFeedback || ''} | ${c.total} |`).join('\n')); setShowMonthPanel(true); };
  const handleExportBackup = () => { const blob = new Blob([JSON.stringify(monthlyData, null, 2)], { type: 'application/json' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'kubarev_backup.json'; a.click(); };
  const handleImportBackup = (e) => { const file = e.target.files?.[0]; if (!file) return; const r = new FileReader(); r.onload = (ev) => { try { const d = JSON.parse(ev.target.result); setMonthlyData(d); saveMonthlyData(d); alert('✅ Восстановлено.'); } catch { alert('❌ Неверный формат.'); } }; r.readAsText(file); e.target.value = ''; };
  const addGoal = () => { if (!newGoal.trim()) return; const upd = [...goals, { text: newGoal.trim(), done: false, date: new Date().toLocaleString('ru-RU') }]; setGoals(upd); localStorage.setItem(GOALS_KEY, JSON.stringify(upd)); setNewGoal(''); };
  const toggleGoal = (i) => { const upd = [...goals]; upd[i].done = !upd[i].done; setGoals(upd); localStorage.setItem(GOALS_KEY, JSON.stringify(upd)); };
  const deleteGoal = (i) => { const upd = goals.filter((_, j) => j !== i); setGoals(upd); localStorage.setItem(GOALS_KEY, JSON.stringify(upd)); };
  const handleExportPdf = async () => { if (!dashboardRef.current) return; const canvas = await html2canvas(dashboardRef.current, { backgroundColor: theme === 'dark' ? '#0f172a' : '#f8fafc', scale: 2 }); const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' }); pdf.addImage(canvas.toDataURL('image/png'), 'PNG', 0, 0, pdf.internal.pageSize.getWidth(), (canvas.height * pdf.internal.pageSize.getWidth()) / canvas.width); pdf.save('logistics_dashboard_report.pdf'); };

  const allParsed = useMemo(() => { const rows = parseMarkdownTable(rawText, managerFilter); let e = 0; for (const r of rows) { if (r.total > 0 && (r.order + r.dealFell + r.priceFail + r.slowCalc + r.clientSilent + r.formal + r.noFeedback) !== r.total) e++; } setValErr(e); return rows; }, [rawText]);
  const parsed = useMemo(() => applyFilters(allParsed, catF, mc, yF, mnF), [allParsed, catF, mc, yF, mnF]);
  const allMonthKeys = useMemo(() => sortMonths([...new Set(allParsed.map(r => r.month))]), [allParsed]);
  const prevP = useMemo(() => { if (!allMonthKeys.length || allMonthKeys.length < 2) return null; return allParsed.filter(r => r.month !== allMonthKeys[allMonthKeys.length - 1]); }, [allParsed, allMonthKeys]);

  const handleFileUpload = async (e) => { const file = e.target.files?.[0]; if (!file) return; setIsLoading(true); setExcelFileName(file.name); try { const md = await loadExcelAsMarkdown(file, { onlyKubarev: true }); setRawText(md); setDataSource('excel'); saveToHistory(file.name, md); const pr = parseMarkdownTable(md, managerFilter); const nd = {}; for (const r of pr) { if (!nd[r.month]) nd[r.month] = { manager: managerFilter, categories: [] }; nd[r.month].categories.push({ category: r.category, order: r.order, dealFell: r.dealFell, priceFail: r.priceFail, slowCalc: r.slowCalc, clientSilent: r.clientSilent, formal: r.formal, noFeedback: r.noFeedback, total: r.total }); } const merged = { ...monthlyData, ...nd }; setMonthlyData(merged); saveMonthlyData(merged); } catch (err) { alert('❌ Не удалось прочитать Excel.'); } finally { setIsLoading(false); if (fileInputRef.current) fileInputRef.current.value = ''; } };
  const saveToHistory = useCallback((name, text) => { const c = parseMarkdownTable(text, managerFilter).reduce((s, r) => s + r.total, 0); setHistory(p => { const u = [{ name, date: new Date().toLocaleString('ru-RU'), count: c, text }, ...p.filter(h => h.text !== text)].slice(0, MAX_HISTORY); localStorage.setItem(HISTORY_KEY, JSON.stringify(u)); return u; }); }, []);
  const loadFromHistory = (e) => { setRawText(e.text); setDataSource('history'); };
  const handleDownloadMd = () => { const b = new Blob([rawText], { type: 'text/markdown;charset=utf-8' }); const a = document.createElement('a'); a.href = URL.createObjectURL(b); a.download = 'kubarev_data.md'; a.click(); };

  const totalRequests = useMemo(() => parsed.reduce((s, r) => s + r.total, 0), [parsed]); const totalOrders = useMemo(() => parsed.reduce((s, r) => s + r.order, 0), [parsed]);
  const conversion = totalRequests > 0 ? ((totalOrders / totalRequests) * 100).toFixed(1) : '0'; const junkT = useMemo(() => parsed.reduce((s, r) => s + r.formal + r.noFeedback, 0), [parsed]);
  const csT = useMemo(() => parsed.reduce((s, r) => s + r.clientSilent, 0), [parsed]); const wastedH = +((junkT + csT) * 7 / 60).toFixed(1);
  const junkPct = totalRequests > 0 ? ((junkT / totalRequests) * 100).toFixed(1) : '0'; const uM = useMemo(() => new Set(parsed.map(r => r.month)).size, [parsed]);
  const avgM = uM > 0 ? Math.round(totalRequests / uM) : 0; const ordSh = totalRequests > 0 ? ((totalOrders / totalRequests) * 100) : 0;
  const healthI = Math.min(100, Math.round((+conversion / 33) * (1 - +junkPct / 100) * (ordSh / 100) * 100));
  const healthC = healthI >= 70 ? 'text-green-600' : healthI >= 40 ? 'text-yellow-600' : 'text-red-600';
  const prevT = prevP ? prevP.reduce((s, r) => s + r.total, 0) : 0; const prevO = prevP ? prevP.reduce((s, r) => s + r.order, 0) : 0;
  const prevC = prevT > 0 ? ((prevO / prevT) * 100).toFixed(1) : '0'; const prevJ = prevP ? prevP.reduce((s, r) => s + r.formal + r.noFeedback, 0) : 0;
  const prevJP = prevT > 0 ? ((prevJ / prevT) * 100).toFixed(1) : '0';
  const whatIf = useMemo(() => { const rw = (junkT + csT) * (wasteReduction / 100); return (totalRequests - rw) > 0 ? ((totalOrders / (totalRequests - rw)) * 100).toFixed(1) : conversion; }, [totalRequests, totalOrders, junkT, csT, wasteReduction, conversion]);
  const catData = useMemo(() => aggregateByCategory(parsed), [parsed]); const lossR = useMemo(() => aggregateLossReasons(parsed), [parsed]);
  const monthData = useMemo(() => aggregateByMonth(parsed), [parsed]); const insights = useMemo(() => generateInsights(parsed), [parsed]);
  const savedMonths = useMemo(() => sortMonths(Object.keys(monthlyData)), [monthlyData]);
  const availYears = [...new Set(allParsed.map(r => r.month.split(' ')[1]))].sort();
  const strengthInsights = insights.filter(i => i.category === 'strength'); const attentionInsights = insights.filter(i => i.category === 'attention');

  const AI_SYSTEM_PROMPT = `Ты — AI-ассистент логиста Кубарева Михаила, закупщика и продуктолога в российской логистической компании. Твоя роль: помогать Михаилу анализировать данные по запросам ставок и находить точки роста. 📦 Контекст о Михаиле: работает в компании TETRATRANS.RU с августа 2023 года. Специализация: прямое ЖД из Китая в РФ (импорт). Опыт в логистике: 5-6 лет. В начале 2025 года взял продукт «прямое ЖД» и полностью перестроил процесс. 🔄 Процесс: 1. ОП присылает запрос → 2. Михаил отправляет 4 агентам → 3. Сравнивает ставки → 4. Отдаёт лучшие ОП → 5. Сопровождает перевозку. 🌟 Сильные стороны: очень быстрый, проактивный, знает английский, учит китайский. 📊 Как отвечать: КРАТКО, с эмодзи, структура: 📊Анализ → 💡Рекомендации. 🚫 НЕЛЬЗЯ упоминать зарплату и доходы.`;
  const openChat = () => { setShowChat(true); if (!chatMessages.length) setChatMessages([{ role: 'assistant', content: `👋 Привет, Михаил! Я — твой AI-ассистент по логистике.\n\n📊 Вижу данные:\n• ${totalRequests} запросов за ${uM} мес.\n• Конверсия: ${conversion}%\n• Формальные запросы: ${junkPct}%\n• ${wastedH} ч впустую\n\nСпроси меня о чём угодно — помогу найти точки роста. 🚀` }]); };
  const sendChat = async () => { const tx = chatInput.trim(); if (!tx || chatLoading) return; const nm = [...chatMessages, { role: 'user', content: tx }]; setChatMessages(nm); setChatInput(''); setChatLoading(true); try { const r = await fetch('https://api.deepseek.com/v1/chat/completions', { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` }, body: JSON.stringify({ model: 'deepseek-v4-pro', messages: [{ role: 'system', content: AI_SYSTEM_PROMPT }, ...nm.map(m => ({ role: m.role, content: m.content }))] }) }); const d = await r.json(); setChatMessages(p => [...p, { role: 'assistant', content: d.choices?.[0]?.message?.content || '⚠️ Ошибка API.' }]); } catch { setChatMessages(p => [...p, { role: 'assistant', content: '❌ Ошибка соединения.' }]); } finally { setChatLoading(false); } };

  const toggleSeries = (dk) => setHiddenSeries(p => { const n = new Set(p); n.has(dk) ? n.delete(dk) : n.add(dk); return n; });
  const renderLegend = (props) => <ul className="flex flex-wrap justify-center gap-4 mt-2">{props.payload.map((e, i) => <li key={i} className={`flex items-center gap-2 text-sm cursor-pointer transition-opacity ${hiddenSeries.has(e.dataKey || e.value) ? 'opacity-30' : 'opacity-100'}`} onClick={() => toggleSeries(e.dataKey || e.value)}><span className="w-3 h-3 rounded-full" style={{ backgroundColor: e.color }}></span><span className="text-slate-600 dark:text-slate-300">{e.value}</span></li>)}</ul>;

  const kpiCards = [
    { title: 'Всего запросов', value: totalRequests, icon: Target, color: 'text-blue-600 dark:text-blue-400', sc: '#3b82f6', sk: 'total', formula: 'Сумма всех запросов за выбранный период.', trend: prevP ? <TrendArrow current={totalRequests} previous={prevT} /> : null },
    { title: 'Конверсия в заказ', value: conversion, isPercent: true, icon: TrendingUp, color: 'text-green-600 dark:text-green-400', sc: '#22c55e', sk: 'conversion', formula: 'Заказы / Всего запросов × 100%. Цель: 15%+.', trend: prevP ? <TrendArrow current={+conversion} previous={+prevC} /> : null },
    { title: 'Формальные запросы', value: junkPct, isPercent: true, icon: AlertTriangle, color: 'text-red-600 dark:text-red-400', sc: '#ef4444', sk: 'junkPct', invertSpark: true, formula: 'Формальные запросы + Нет обратной связи. Не ведут к сделке — трата времени.', trend: prevP ? <TrendArrow current={+junkPct} previous={+prevJP} invert /> : null },
    { title: 'Время впустую', value: wastedH, icon: Clock, color: 'text-orange-600 dark:text-orange-400', sc: '#f97316', sk: 'noFeedbackRaw', formula: '(Формальные запросы + Клиент не отвечает) × 7 мин / 60.', suffix: ' ч' },
    { title: 'Среднее в месяц', value: avgM, icon: Activity, color: 'text-violet-600 dark:text-violet-400', sc: '#8b5cf6', sk: 'total', formula: 'Всего запросов / Количество месяцев.' },
    { title: 'Месяцев данных', value: uM, icon: Calendar, color: 'text-amber-600 dark:text-amber-400', sc: '#f59e0b', sk: 'total', formula: 'Количество уникальных месяцев.' },
  ];

  return (
    <div ref={dashboardRef} className="min-h-screen bg-slate-50 dark:bg-slate-900 p-4 md:p-8 font-sans text-slate-900 dark:text-slate-100 print:bg-white print:p-2 transition-colors duration-200">
      <header className="mb-6 print:mb-2 flex justify-between items-start"><div><h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2"><span className="text-blue-600 dark:text-blue-500">📊</span> Логистический Дашборд</h1><p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Аналитика запросов Кубарева Михаила • {uM} месяцев данных</p></div><div className="flex items-center gap-2 no-print">{isAdmin&&<span className="text-xs bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 px-2 py-0.5 rounded-full font-medium flex items-center gap-1"><Shield className="w-3 h-3"/>Админ</span>}{!isAdmin&&<span className="text-xs bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 px-2 py-0.5 rounded-full font-medium flex items-center gap-1"><User className="w-3 h-3"/>Гость</span>}{!isAdmin?<button onClick={()=>setShowLogin(true)} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"><LogIn className="w-4 h-4"/></button>:<button onClick={handleLogout} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"><LogOut className="w-4 h-4"/></button>}{isAdmin&&<button onClick={()=>setShowSettings(true)} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors"><Settings className="w-5 h-5"/></button>}<button onClick={()=>{setTheme(p=>p==='light'?'dark':'light');setThemeManual(true);}} className="p-2 rounded-full bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700 transition-colors">{theme==='light'?<Moon className="w-5 h-5"/>:<Sun className="w-5 h-5"/>}</button><button onClick={()=>showChat?setShowChat(false):openChat()} className={`p-2 rounded-full transition-colors ${showChat?'bg-blue-600 text-white':'bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-700'}`}><MessageSquare className="w-5 h-5"/></button></div></header>
      {showUpdateReminder&&isAdmin&&<div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-300 dark:border-amber-700 p-3 rounded-2xl mb-4 flex items-center gap-3 text-sm text-amber-800 dark:text-amber-300"><Bell className="w-4 h-4 flex-shrink-0"/><span>Последние данные не за текущий месяц. <button onClick={()=>{setShowMonthPanel(true);setShowUpdateReminder(false);}} className="underline font-medium">Добавь новый месяц</button>.</span><button onClick={()=>setShowUpdateReminder(false)} className="ml-auto p-1"><X className="w-3 h-3"/></button></div>}
      <section className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 mb-6 print:hidden"><div className="flex items-center justify-between mb-3 flex-wrap gap-2"><h2 className="text-lg font-semibold flex items-center gap-2 dark:text-slate-100"><FileSpreadsheet className="w-5 h-5 text-blue-500"/>Импорт данных</h2><div className="flex items-center gap-2 text-xs text-slate-500 dark:text-slate-400"><span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full font-medium ${dataSource==='excel'?'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400':dataSource==='history'?'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400':'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'}`}><FileText className="w-3 h-3"/>{dataSource==='excel'?`Excel: ${excelFileName}`:dataSource==='history'?'История':'Markdown'}</span>{isLoading&&<span className="text-amber-600 dark:text-amber-400 animate-pulse">⏳ Конвертация...</span>}</div></div><textarea className="w-full h-36 p-4 border border-slate-200 dark:border-slate-600 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none mb-4 font-mono text-xs resize-y bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100" placeholder="Вставьте Markdown-таблицу или загрузите .xlsx..." value={rawText} onChange={e=>{setRawText(e.target.value);setDataSource('markdown');}}/>{history.length>0&&<div className="mb-3"><p className="text-xs text-slate-400 dark:text-slate-500 mb-1 flex items-center gap-1"><Clock className="w-3 h-3"/>История:</p><div className="flex flex-wrap gap-2">{history.map((h,i)=><button key={i} onClick={()=>loadFromHistory(h)} className="text-xs bg-slate-100 dark:bg-slate-700 hover:bg-slate-200 dark:hover:bg-slate-600 px-2 py-1 rounded-lg border border-slate-200 dark:border-slate-600 transition text-left dark:text-slate-200"><span className="font-medium">{h.name}</span><span className="text-slate-400 dark:text-slate-500 ml-1">{h.date}</span><span className="text-slate-500 dark:text-slate-400 ml-1">({h.count} запр.)</span></button>)}</div></div>}<div className="flex items-center gap-3 flex-wrap"><input ref={fileInputRef} type="file" accept=".xlsx,.xls" onChange={handleFileUpload} className="hidden"/><button onClick={()=>fileInputRef.current?.click()} disabled={isLoading} className="inline-flex items-center gap-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-medium hover:bg-slate-50 dark:hover:bg-slate-700 transition active:scale-95 disabled:opacity-50"><Upload className="w-4 h-4"/>{isLoading?'Загрузка...':'Загрузить .xlsx'}</button><button onClick={handleDownloadMd} className="inline-flex items-center gap-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-200 px-4 py-2.5 rounded-xl font-medium hover:bg-slate-50 dark:hover:bg-slate-700 transition active:scale-95"><Download className="w-4 h-4"/>Скачать .md</button><button onClick={handleExportPdf} className="inline-flex items-center gap-2 bg-rose-600 text-white px-4 py-2.5 rounded-xl font-medium hover:bg-rose-700 transition active:scale-95"><FileDown className="w-4 h-4"/>Экспорт в PDF</button>{isAdmin&&<button onClick={()=>setShowMonthPanel(true)} className="inline-flex items-center gap-2 bg-emerald-600 text-white px-4 py-2.5 rounded-xl font-medium hover:bg-emerald-700 transition active:scale-95"><Database className="w-4 h-4"/>Управление месяцами</button>}<span className="text-xs text-slate-400 dark:text-slate-500 ml-auto">Строк: <strong className="text-slate-600 dark:text-slate-300">{parsed.length}</strong>{valErr>0&&<><span className="mx-1">|</span><span className="text-red-500">⚠️ Ошибок: {valErr}</span></>}{valErr===0&&parsed.length>0&&<span className="text-green-500 ml-1">✓</span>}</span></div></section>
      {isAdmin&&savedMonths.length>0&&<section className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 mb-6 print:hidden"><div className="flex items-center justify-between mb-2"><h3 className="text-sm font-semibold dark:text-slate-200">Сохранённые месяцы ({savedMonths.length})</h3><div className="flex gap-2"><button onClick={handleExportBackup} className="text-xs text-blue-600 hover:underline">📥 Бэкап</button><label className="text-xs text-blue-600 hover:underline cursor-pointer">📤 Восстановить<input type="file" accept=".json" onChange={handleImportBackup} className="hidden"/></label></div></div><div className="flex flex-wrap gap-2">{savedMonths.map(m=><div key={m} className="flex items-center gap-1 bg-slate-100 dark:bg-slate-700 rounded-lg px-3 py-1.5 text-xs"><span className="text-slate-700 dark:text-slate-200">{m}</span><button onClick={()=>handleOverwriteMonth(m)} className="text-slate-400 hover:text-blue-500"><Edit3 className="w-3 h-3"/></button><button onClick={()=>handleDeleteMonth(m)} className="text-slate-400 hover:text-red-500"><Trash2 className="w-3 h-3"/></button></div>)}</div></section>}
      <section className="flex flex-wrap items-center gap-4 mb-6 print:hidden"><div className="flex items-center gap-2"><Filter className="w-4 h-4 text-slate-400"/><span className="text-sm text-slate-500 dark:text-slate-400">Фильтры:</span></div><select value={catF} onChange={e=>setCatF(e.target.value)} className="text-sm border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-1.5 bg-white dark:bg-slate-800 dark:text-slate-200"><option value="all">Все категории</option><option value="ИМПОРТ - запрос ставки прямое ж/д">Прямое ЖД</option><option value="ИМПОРТ - запрос ставки морского фрахта">Морской фрахт</option><option value="ИМПОРТ - запрос ставки морского фрахта (опасный груз)">Морской фрахт (опасный)</option><option value="ИМПОРТ - запрос скидки на морской фрахт">Скидки</option></select><select value={yF} onChange={e=>setYF(e.target.value)} className="text-sm border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-1.5 bg-white dark:bg-slate-800 dark:text-slate-200"><option value="all">Все годы</option>{availYears.map(y=><option key={y} value={y}>{y}</option>)}</select><select value={mnF} onChange={e=>setMnF(e.target.value)} className="text-sm border border-slate-200 dark:border-slate-700 rounded-xl px-3 py-1.5 bg-white dark:bg-slate-800 dark:text-slate-200"><option value="all">Все месяцы</option>{['январь','февраль','март','апрель','май','июнь','июль','август','сентябрь','октябрь','ноябрь','декабрь'].map(m=><option key={m} value={m}>{m}</option>)}</select><div className="flex items-center gap-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl p-0.5">{[{label:'Все',value:0},{label:'12',value:12},{label:'6',value:6},{label:'3',value:3}].map(opt=><button key={opt.value} onClick={()=>setMc(opt.value)} className={`text-sm px-3 py-1 rounded-lg transition ${mc===opt.value?'bg-blue-600 text-white':'text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700'}`}>{opt.label}</button>)}</div></section>
      <section className="grid grid-cols-2 md:grid-cols-6 gap-3 mb-3 print:grid-cols-6">{isLoading?Array(6).fill(0).map((_,i)=><div key={i} className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-center gap-3 animate-pulse-soft"><div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700"></div><div className="space-y-2 flex-1"><div className="h-3 bg-slate-200 dark:bg-slate-700 rounded w-1/2"></div><div className="h-5 bg-slate-200 dark:bg-slate-700 rounded w-3/4"></div></div></div>):kpiCards.map((kpi,i)=><KpiTooltip key={i} formula={kpi.formula} sparkData={monthData.slice(-6)} sparkColor={kpi.sc} sparkKey={kpi.sk} invertSpark={kpi.invertSpark}><div className="bg-white dark:bg-slate-800 p-4 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-center gap-3 hover:shadow-md hover:-translate-y-0.5 transition-all duration-200 cursor-help"><div className={`p-2 rounded-full bg-slate-100 dark:bg-slate-700 ${kpi.color}`}><kpi.icon className="w-4 h-4"/></div><div className="flex-1"><p className="text-xs text-slate-500 dark:text-slate-400">{kpi.title}</p><div className="flex items-center justify-between"><p className="text-lg font-bold flex items-center gap-1.5 dark:text-slate-100"><AnimatedNumber value={kpi.value} isPercent={kpi.isPercent}/>{kpi.suffix}{kpi.trend}</p><div className="opacity-50"><Sparkline data={monthData.slice(-6)} dataKey={kpi.sk} color={kpi.sc} invert={kpi.invertSpark}/></div></div></div></div></KpiTooltip>)}</section>
      <section className="mb-6"><div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><div className="flex items-center justify-between"><div className="flex items-center gap-3"><div className="p-2 rounded-full bg-slate-100 dark:bg-slate-700"><Zap className={`w-5 h-5 ${healthC}`}/></div><div><p className="text-sm text-slate-500 dark:text-slate-400">Индекс здоровья закупщика <span className="text-xs text-slate-400">(Конверсия / 33% × (1 − Формальные запросы %) × Доля заказов)</span></p><p className="text-2xl font-bold flex items-center gap-2 dark:text-slate-100"><AnimatedNumber value={healthI}/><span className={`text-sm ${healthC}`}>/ 100</span></p></div></div></div><div className="mt-3 h-2 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden"><div className={`h-full rounded-full transition-all duration-500 ${healthI>=70?'bg-green-500':healthI>=40?'bg-yellow-500':'bg-red-500'}`} style={{width:`${healthI}%`}}></div></div></div></section>
      <section className="mb-6"><div className="bg-white dark:bg-slate-800 p-5 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><h3 className="font-semibold mb-3 dark:text-slate-100 flex items-center gap-2"><Flag className="w-4 h-4 text-amber-500"/>Мои цели</h3><div className="space-y-2 mb-3">{goals.length===0&&<p className="text-xs text-slate-400 dark:text-slate-500">Целей пока нет.</p>}{goals.map((g,i)=><div key={i} className="flex items-center gap-2 text-sm"><button onClick={()=>toggleGoal(i)} className={`w-4 h-4 rounded border flex-shrink-0 ${g.done?'bg-green-500 border-green-500':'border-slate-300 dark:border-slate-600'}`}>{g.done&&<CheckCircle className="w-4 h-4 text-white"/>}</button><span className={`flex-1 ${g.done?'line-through text-slate-400':'dark:text-slate-200'}`}>{g.text}</span><span className="text-xs text-slate-400">{g.date}</span><button onClick={()=>deleteGoal(i)} className="text-slate-400 hover:text-red-500"><X className="w-3 h-3"/></button></div>)}</div><div className="flex gap-2"><input value={newGoal} onChange={e=>setNewGoal(e.target.value)} onKeyDown={e=>e.key==='Enter'&&addGoal()} placeholder="Новая цель..." className="flex-1 p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100"/><button onClick={addGoal} className="bg-amber-500 text-white px-4 py-2 rounded-xl font-medium hover:bg-amber-600"><Plus className="w-4 h-4"/></button></div></div></section>
      <section className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-6 print:grid-cols-2"><div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><h3 className="font-semibold mb-4 dark:text-slate-100">Причины потери сделок</h3><div className="h-72 print:h-48">{isLoading?<div className="w-full h-full bg-slate-100 dark:bg-slate-700 rounded-full animate-pulse-soft scale-75"></div>:lossR.length>0?<ResponsiveContainer width="100%" height="100%"><PieChart><Pie data={lossR} innerRadius={55} outerRadius={85} paddingAngle={3} dataKey="value" label={({name,percent})=>`${name} ${(percent*100).toFixed(0)}%`}>{lossR.map((e,i)=><Cell key={i} fill={PIE_COLORS[i%PIE_COLORS.length]} className={hiddenSeries.has(e.name)?'opacity-0':'opacity-100'}/>)}</Pie><Tooltip contentStyle={{backgroundColor:theme==='dark'?'#1e293b':'#fff',borderColor:theme==='dark'?'#334155':'#e2e8f0',color:theme==='dark'?'#f8fafc':'#0f172a'}}/><Legend content={renderLegend}/></PieChart></ResponsiveContainer>:<div className="flex items-center justify-center h-full text-slate-400">Нет данных</div>}</div></div><div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><h3 className="font-semibold mb-4 dark:text-slate-100">Категории запросов</h3><div className="h-72 print:h-48">{isLoading?<div className="w-full h-full flex items-end gap-2 animate-pulse-soft">{Array(5).fill(0).map((_,i)=><div key={i} className="flex-1 bg-slate-200 dark:bg-slate-700 rounded-t-md" style={{height:`${Math.random()*60+20}%`}}></div>)}</div>:catData.length>0?<ResponsiveContainer width="100%" height="100%"><BarChart data={catData} barSize={50}><CartesianGrid strokeDasharray="3 3" stroke={theme==='dark'?'#334155':'#e2e8f0'}/><XAxis dataKey="name" tick={{fontSize:11,fill:theme==='dark'?'#94a3b8':'#64748b'}}/><YAxis tick={{fill:theme==='dark'?'#94a3b8':'#64748b'}}/><Tooltip contentStyle={{backgroundColor:theme==='dark'?'#1e293b':'#fff',borderColor:theme==='dark'?'#334155':'#e2e8f0',color:theme==='dark'?'#f8fafc':'#0f172a'}}/><Legend content={renderLegend}/><Bar dataKey="Заказ" stackId="a" fill="#22c55e" hide={hiddenSeries.has('Заказ')}/><Bar dataKey="Сделка сорвалась" stackId="a" fill="#eab308" hide={hiddenSeries.has('Сделка сорвалась')}/><Bar dataKey="Не прошли по цене" stackId="a" fill="#ef4444" hide={hiddenSeries.has('Не прошли по цене')}/><Bar dataKey="Прочие потери" stackId="a" fill="#f97316" hide={hiddenSeries.has('Прочие потери')}/></BarChart></ResponsiveContainer>:<div className="flex items-center justify-center h-full text-slate-400">Нет данных</div>}</div></div></section>
      <section className="mb-6"><div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><h3 className="font-semibold mb-4 dark:text-slate-100">Динамика по месяцам</h3><div className="h-80 print:h-48">{isLoading?<div className="w-full h-full bg-slate-100 dark:bg-slate-700 rounded-lg animate-pulse-soft"></div>:monthData.length>0?<ResponsiveContainer width="100%" height="100%"><LineChart data={monthData}><CartesianGrid strokeDasharray="3 3" stroke={theme==='dark'?'#334155':'#e2e8f0'}/><XAxis dataKey="month" tick={{fontSize:11,fill:theme==='dark'?'#94a3b8':'#64748b'}}/><YAxis tick={{fill:theme==='dark'?'#94a3b8':'#64748b'}}/><Tooltip contentStyle={{backgroundColor:theme==='dark'?'#1e293b':'#fff',borderColor:theme==='dark'?'#334155':'#e2e8f0',color:theme==='dark'?'#f8fafc':'#0f172a'}}/><Legend content={renderLegend}/><ReferenceLine y={15} stroke="#ef4444" strokeDasharray="6 6" strokeWidth={1.5} label={{value:'Цель 15%',position:'top',fill:theme==='dark'?'#f87171':'#ef4444',fontSize:11}}/>{Object.entries(MONTH_COLORS).map(([key,color])=><Line key={key} type="monotone" dataKey={key} stroke={color} strokeWidth={2} dot={{r:4}} hide={hiddenSeries.has(key)}/>)}</LineChart></ResponsiveContainer>:<div className="flex items-center justify-center h-full text-slate-400">Нет данных</div>}</div></div></section>
      {!isLoading&&<Heatmap data={monthData}/>}
      {!isLoading&&totalRequests>0&&<section className="mb-6"><div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700"><h3 className="font-semibold mb-4 dark:text-slate-100 flex items-center gap-2"><Sliders className="w-4 h-4 text-purple-500"/>What-if</h3><p className="text-sm text-slate-500 dark:text-slate-400 mb-3">Сократить формальные запросы на <strong>{wasteReduction}%</strong> → прогнозная конверсия:</p><div className="flex items-center gap-4"><input type="range" min="0" max="100" value={wasteReduction} onChange={e=>setWasteReduction(+e.target.value)} className="flex-1 accent-blue-600"/><span className="text-xl font-bold text-green-600 dark:text-green-400 min-w-[70px] text-right">{whatIf}%</span></div></div></section>}
      <section className="mb-6"><h3 className="font-semibold mb-4 flex items-center gap-2 dark:text-slate-100"><span className="text-purple-600">💡</span>Умные подсказки</h3>{isLoading?<div className="space-y-3">{Array(2).fill(0).map((_,i)=><div key={i} className="h-20 bg-slate-200 dark:bg-slate-700 rounded-xl animate-pulse-soft"></div>)}</div>:(strengthInsights.length>0||attentionInsights.length>0)?<div className="grid grid-cols-1 lg:grid-cols-2 gap-6"><div className="space-y-3"><h4 className="text-sm font-semibold text-emerald-700 dark:text-emerald-300 flex items-center gap-2"><CheckCircle className="w-4 h-4"/>Сильные стороны</h4>{strengthInsights.length>0?strengthInsights.map((ins,i)=><InsightCard key={i} insight={ins}/>):<p className="text-xs text-slate-400 dark:text-slate-500 p-4 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700">Пока не выявлены — добавь больше данных.</p>}</div><div className="space-y-3"><h4 className="text-sm font-semibold text-amber-700 dark:text-amber-300 flex items-center gap-2"><AlertTriangle className="w-4 h-4"/>Над чем поработать</h4>{attentionInsights.length>0?attentionInsights.map((ins,i)=><InsightCard key={i} insight={ins}/>):<p className="text-xs text-slate-400 dark:text-slate-500 p-4 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700">Проблем не обнаружено — отличная работа!</p>}</div></div>:<div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 text-center text-slate-400">✅ Все показатели в норме.</div>}</section>
      <button onClick={()=>showChat?setShowChat(false):openChat()} className={`fixed bottom-6 right-6 z-30 p-4 rounded-full shadow-lg transition-all duration-200 hover:scale-105 active:scale-95 no-print ${showChat?'bg-slate-500 text-white':'bg-blue-600 text-white hover:bg-blue-700'}`} title="Спросить AI"><MessageSquare className="w-6 h-6"/></button>
      {showLogin&&<div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={()=>setShowLogin(false)}><div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-6 w-full max-w-sm mx-4" onClick={e=>e.stopPropagation()}><div className="flex items-center justify-between mb-4"><h2 className="text-lg font-bold dark:text-slate-100"><Shield className="inline w-4 h-4 mr-1"/>Вход</h2><button onClick={()=>setShowLogin(false)} className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"><X className="w-4 h-4 dark:text-slate-300"/></button></div><div className="space-y-3"><input type="text" placeholder="Логин" value={loginUser} onChange={e=>setLoginUser(e.target.value)} className="w-full p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100"/><input type="password" placeholder="Пароль" value={loginPass} onChange={e=>setLoginPass(e.target.value)} onKeyDown={e=>e.key==='Enter'&&handleLogin()} className="w-full p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100"/>{loginError&&<p className="text-red-500 text-xs">{loginError}</p>}<button onClick={handleLogin} className="w-full bg-blue-600 text-white py-2 rounded-xl font-medium hover:bg-blue-700">Войти</button></div></div></div>}
      {showSettings&&isAdmin&&<div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={()=>setShowSettings(false)}><div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-6 w-full max-w-md mx-4" onClick={e=>e.stopPropagation()}><div className="flex items-center justify-between mb-4"><h2 className="text-lg font-bold dark:text-slate-100"><Settings className="inline w-4 h-4 mr-1"/>Настройки</h2><button onClick={()=>setShowSettings(false)} className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"><X className="w-4 h-4 dark:text-slate-300"/></button></div><div className="space-y-4"><div><label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">DeepSeek API-ключ</label><input type="password" value={apiKey} onChange={e=>{setApiKey(e.target.value);localStorage.setItem(API_KEY_STORAGE,e.target.value);}} placeholder="sk-..." className="w-full p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100"/><p className="text-xs text-slate-400 mt-1">Ключ хранится локально.</p></div><div className="text-xs text-slate-400 dark:text-slate-500">Модель: <strong>deepseek-v4-pro</strong></div></div></div></div>}
      {showMonthPanel&&<div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" onClick={()=>{setShowMonthPanel(false);setEditingMonth(null);setMonthExcelName('');}}><div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl p-6 w-full max-w-lg mx-4" onClick={e=>e.stopPropagation()}><div className="flex items-center justify-between mb-4"><h2 className="text-lg font-bold dark:text-slate-100"><Plus className="inline w-4 h-4 mr-1"/>{editingMonth?`Перезаписать: ${editingMonth}`:'Добавить месяц'}</h2><button onClick={()=>{setShowMonthPanel(false);setEditingMonth(null);setMonthExcelName('');}} className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"><X className="w-4 h-4 dark:text-slate-300"/></button></div><div className="space-y-3"><input type="text" placeholder="Название месяца (например: май 2026)" value={newMonthName} onChange={e=>setNewMonthName(e.target.value)} className="w-full p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100"/><input ref={monthFileInputRef} type="file" accept=".xlsx,.xls" onChange={handleMonthExcelUpload} className="hidden"/><button onClick={()=>monthFileInputRef.current?.click()} className="w-full inline-flex items-center justify-center gap-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 text-slate-700 dark:text-slate-200 px-4 py-2 rounded-xl font-medium hover:bg-slate-50 dark:hover:bg-slate-700 transition"><Upload className="w-4 h-4"/>{monthExcelName?`📄 ${monthExcelName}`:'Загрузить .xlsx для этого месяца'}</button><textarea placeholder="Данные появятся после загрузки Excel или вставьте вручную" value={newMonthText} onChange={e=>setNewMonthText(e.target.value)} className="w-full h-32 p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-xs font-mono dark:text-slate-100"/><p className="text-xs text-slate-400">Проверьте данные перед внесением.</p><button onClick={handleAddMonth} className="w-full bg-emerald-600 text-white py-2 rounded-xl font-medium hover:bg-emerald-700 transition">{editingMonth?'Сохранить изменения':'Внести данные'}</button></div></div></div>}
      {showChat&&<div className="fixed inset-0 z-40 flex justify-end"><div className="absolute inset-0 bg-black/30" onClick={()=>setShowChat(false)}></div><div className="relative w-full max-w-[400px] bg-white dark:bg-slate-800 h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300"><div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700"><h3 className="font-semibold dark:text-slate-100 flex items-center gap-2"><MessageSquare className="w-4 h-4 text-blue-500"/>AI-ассистент</h3><div className="flex items-center gap-2">{!apiKey&&<span className="text-xs text-red-400">Нет ключа</span>}<button onClick={()=>setShowChat(false)} className="p-1 hover:bg-slate-100 dark:hover:bg-slate-700 rounded"><X className="w-4 h-4 dark:text-slate-300"/></button></div></div><div className="flex-1 overflow-y-auto p-4 space-y-3">{chatMessages.map((m,i)=><div key={i} className={`flex ${m.role==='user'?'justify-end':'justify-start'}`}><div className={`max-w-[85%] rounded-2xl px-3 py-2 text-sm whitespace-pre-wrap ${m.role==='user'?'bg-blue-600 text-white':'bg-slate-100 dark:bg-slate-700 text-slate-800 dark:text-slate-200'}`}>{m.content}</div></div>)}{chatLoading&&<div className="text-sm text-slate-400 animate-pulse">⏳ Думаю...</div>}<div ref={chatEndRef}/></div><div className="p-4 border-t border-slate-200 dark:border-slate-700"><div className="flex gap-2"><input value={chatInput} onChange={e=>setChatInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&sendChat()} placeholder={apiKey?'Спроси о данных...':'Вставь API-ключ в настройках'} disabled={!apiKey} className="flex-1 p-2 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-sm dark:text-slate-100 focus:ring-2 focus:ring-blue-500 outline-none disabled:opacity-50"/><button onClick={sendChat} disabled={!apiKey||chatLoading} className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition disabled:opacity-50"><Send className="w-4 h-4"/></button></div></div></div></div>}
    </div>
  );
};

export default Dashboard;
